Create a `CreateIndex.cpp` file in your project directory,
and copy and paste the following code into the file.```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

int main() {
    // Initialize the MongoDB C++ driver
    mongocxx::instance instance{};

    // Connect to your MongoDB deployment
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["<database>"];
    auto collection = db["<collection>"];
    auto siv = collection.search_indexes();

    // Create the MongoDB Search index definition for the embeddedDocuments field
    auto name = "default";
    auto definition = make_document(
        kvp("mappings", make_document(
            kvp("dynamic", true|false) | make_document(kvp("typeset", "<type-set-name>")),
            kvp("fields", make_document(
                kvp("<field-name>", make_document(
                    kvp("type", "embeddedDocuments"),
                    kvp("dynamic", true|false) | make_document(kvp("typeset", "<type-set-name>")),
                    kvp("fields", make_document(
                        kvp("<field-name>", make_document(
                            // <field-mapping-definition>
                        )),
                        // ... additional fields
                    )),
                    kvp("storedSource", true|false) | make_document(kvp("include", bsoncxx::builder::basic::array{"<field-name>", ...})) | make_document(kvp("exclude", bsoncxx::builder::basic::array{"<field-name>", ...}))
                )),
                // ... additional fields
            ))
        )),
        kvp("typeSets", bsoncxx::builder::basic::array{
            make_document(
                kvp("name", "<type-set-name>"),
                kvp("types", bsoncxx::builder::basic::array{
                    make_document(
                        kvp("type", "<field-type>")
                        // ... additional field type configuration
                    )
                    // ... additional types
                })
            )
            // ... additional typeSets
        })
    );
    auto model = mongocxx::search_index_model(name, definition.view());

    try {
        // Execute the command to create the index
        auto result = siv.create_one(model);
        std::cout << "New index name: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error creating Atlas Search index: " << e.what() << std::endl;
    }
}
```Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.Atlas ClusterYour connection string should use the following format:```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```To learn more, see [Driver](connect-via-driver).Local or Self-ManagedYour connection string should use the
following format:```
mongodb://localhost:<port-number>/?directConnection=true
```To learn more, see [Connection Strings](manual/reference/connection-string).

